import javax.naming.*;
import javax.naming.directory.*;
import java.util.HashMap;
import java.util.Map;

public class LDAPUserSearch {

    private static final String LDAP_URL = "ldap://your_ldap_server:port";
    private static final String LDAP_SEARCH_FILTER = "(uid=*)";

    public static Map<String, String> searchUserByUsername(String username) throws Exception {
        InitialContext context = new InitialContext();
        context.addToEnvironment("java.naming.factory.initial", "com.sun.jndi.ldap.LdapCtxFactory");
        context.addToEnvironment("java.naming.provider.url", LDAP_URL);

        DirContext ldapContext = (DirContext) context.lookup("java:comp/env/ldap");

        SearchControls searchControls = new SearchControls();
        searchControls.setSearchScope(SearchControls.SUBTREE_SCOPE);
        searchControls.setReturningAttributes(new String[]{"mail", "displayName", "department"});

        String filter = LDAP_SEARCH_FILTER.replace("*", username);

        NamingEnumeration<SearchResult> searchResult = ldapContext.search("", filter, searchControls);

        if (searchResult.hasMoreElements()) {
            SearchResult result = searchResult.next();
            Attributes attributes = result.getAttributes();

            Map<String, String> userAttributes = new HashMap<>();
            userAttributes.put("email", (String) attributes.get("mail").get());
            userAttributes.put("fullName", (String) attributes.get("displayName").get());
            userAttributes.put("department", (String) attributes.get("department").get());

            return userAttributes;
        }

        return null;
    }
}